private boolean hasCycle(List> graph, int node, 
                        boolean[] visited, boolean[] recStack) {
    visited[node] = true;
    recStack[node] = true;

    for (int neighbor : graph.get(node)) {
        if (!visited[neighbor] && hasCycle(graph, neighbor, visited, recStack)) {
            return true;
        } else if (recStack[neighbor]) {
            return true;
        }
    }

    recStack[node] = false;
    return false;
}

